Workshop 5.5: Frontend Development Learning Objectives In this module, I focused on the following areas:
Understand the React component architecture Implement state management with Zustand Create WebSocket client for real-time updates Build video player with subtitle overlay Implement auto-save functionality Design the video editor interface Prerequisites Workshops 5.1-5.4 completed React and TypeScript knowledge Zustand state management basics WebSocket fundamentals Architecture Context The frontend orchestrates user interactions and displays real-time processing status:
┌─────────────────────────────────────────────────────────────┐ │ FRONTEND │ ├─────────────────────────────────────────────────────────────┤ │ │ │ ┌─────────────┐ ┌─────────────┐ ┌─────────────┐ │ │ │ Upload │───▶│ Store │───▶│ Editor │ │ │ │ Page │ │ (Zustand) │ │ Page │ │ │ └─────────────┘ └──────┬──────┘ └─────────────┘ │ │ │ │ │ ┌──────▼──────┐ │ │ │ WebSocket │ │ │ │ Client │ │ │ └──────┬──────┘ │ │ │ │ │ ┌──────▼──────┐ │ │ │ Video Player │ │ │ │ + Overlay │ │ │ └─────────────┘ │ └─────────────────────────────────────────────────────────────┘ Step 1: Project Structure Folder Organization myapporc/src/ ├── components/ │ ├── ui/ # Reusable UI components │ ├── video/ # Video-specific components │ ├── editor/ # Editor components │ └── ... ├── hooks/ # Custom React hooks ├── interfaces/ # TypeScript interfaces ├── pages/ │ ├── auth/ # Login, Register pages │ ├── dashboard/ # Video list page │ └── editor/ # Video editor page ├── store/ # Zustand stores ├── lib/ # Utilities ├── App.tsx └── main.tsx Step 2: State Management with Zustand Video Store // src/store/use-video-store.ts import { create } from &#39;zustand&#39;; import { persist, createJSONStorage } from &#39;zustand/middleware&#39;; interface VideoItem { videoId: string; title: string; fileName: string; fileUrl: string; videoUrl: string; thumbnailUrl: string | null; status: VideoStatus; processingPercentage: number; voiceUsed: string | null; createdAt: string; updatedAt?: string; } type VideoStatus = | &#39;PROCESSING&#39; | &#39;AWAITING_REVIEW&#39; | &#39;STAGE2_PROCESSING&#39; | &#39;COMPLETED&#39; | &#39;FAILED&#39;; interface VideoStore { // State videos: VideoItem[]; currentVideo: VideoItem | null; // Actions setVideos: (videos: VideoItem[]) =&gt; void; addVideo: (video: VideoItem) =&gt; void; updateVideo: (videoId: string, updates: Partial&lt;VideoItem&gt;) =&gt; void; removeVideo: (videoId: string) =&gt; void; setCurrentVideo: (video: VideoItem | null) =&gt; void; // Progress updates updateProgress: (videoId: string, percentage: number, status?: VideoStatus) =&gt; void; } export const useVideoStore = create&lt;VideoStore&gt;()( persist( (set, get) =&gt; ({ videos: [], currentVideo: null, setVideos: (videos) =&gt; set({ videos }), addVideo: (video) =&gt; set((state) =&gt; ({ videos: [video, ...state.videos] })), updateVideo: (videoId, updates) =&gt; set((state) =&gt; ({ videos: state.videos.map((v) =&gt; v.videoId === videoId ? { ...v, ...updates } : v ), currentVideo: state.currentVideo?.videoId === videoId ? { ...state.currentVideo, ...updates } : state.currentVideo })), removeVideo: (videoId) =&gt; set((state) =&gt; ({ videos: state.videos.filter((v) =&gt; v.videoId !== videoId), currentVideo: state.currentVideo?.videoId === videoId ? null : state.currentVideo })), setCurrentVideo: (video) =&gt; set({ currentVideo: video }), updateProgress: (videoId, percentage, status) =&gt; { const updates: Partial&lt;VideoItem&gt; = { processingPercentage: percentage }; if (status) updates.status = status; get().updateVideo(videoId, updates); } }), { name: &#39;video-storage&#39;, storage: createJSONStorage(() =&gt; localStorage), partialize: (state) =&gt; ({ videos: state.videos }) } ) ); Auth Store // src/store/use-auth-store.ts import { create } from &#39;zustand&#39;; import { persist, createJSONStorage } from &#39;zustand/middleware&#39;; interface User { id: number; email: string; username: string; } interface AuthStore { // State user: User | null; token: string | null; isAuthenticated: boolean; // Actions setUser: (user: User) =&gt; void; setToken: (token: string) =&gt; void; logout: () =&gt; void; } export const useAuthStore = create&lt;AuthStore&gt;()( persist( (set) =&gt; ({ user: null, token: null, isAuthenticated: false, setUser: (user) =&gt; set({ user, isAuthenticated: true }), setToken: (token) =&gt; set({ token }), logout: () =&gt; set({ user: null, token: null, isAuthenticated: false }) }), { name: &#39;auth-storage&#39;, storage: createJSONStorage(() =&gt; localStorage), partialize: (state) =&gt; ({ user: state.user, token: state.token, isAuthenticated: state.isAuthenticated }) } ) ); Zustand State Flow Step 3: WebSocket Client Progress Hook Implementation // src/hooks/useVideoProgress.ts import { useEffect, useRef, useCallback } from &#39;react&#39;; import { useVideoStore } from &#39;@/store/use-video-store&#39;; interface ProgressData { video_id: string; percentage: number; status: string; message: string; stage?: string; error_code?: string; } const WS_URL = import.meta.env.VITE_WS_URL || &#39;ws://localhost:8000&#39;; const RECONNECT_DELAY = 3000; const MAX_RECONNECT_ATTEMPTS = 5; export function useVideoProgress(videoId: string) { const wsRef = useRef&lt;WebSocket | null&gt;(null); const reconnectAttempts = useRef(0); const reconnectTimeout = useRef&lt;NodeJS.Timeout | null&gt;(null); const updateProgress = useVideoStore((state) =&gt; state.updateProgress); const connect = useCallback(() =&gt; { // Skip if already connected if (wsRef.current?.readyState === WebSocket.OPEN) { return; } const ws = new WebSocket(`${WS_URL}/ws/progress/${videoId}`); ws.onopen = () =&gt; { console.log(&#39;[WebSocket] Connected to progress stream&#39;); reconnectAttempts.current = 0; }; ws.onmessage = (event) =&gt; { try { const data: ProgressData = JSON.parse(event.data); // Update store with progress updateProgress( data.video_id, data.percentage, data.status as any ); console.log(`[Progress] ${data.percentage}% - ${data.message}`); // Trigger custom event for other components window.dispatchEvent( new CustomEvent(&#39;video-progress&#39;, { detail: data }) ); } catch (error) { console.error(&#39;[WebSocket] Failed to parse message:&#39;, error); } }; ws.onerror = (error) =&gt; { console.error(&#39;[WebSocket] Error:&#39;, error); }; ws.onclose = () =&gt; { console.log(&#39;[WebSocket] Connection closed&#39;); wsRef.current = null; // Attempt reconnection if not at max attempts if (reconnectAttempts.current &lt; MAX_RECONNECT_ATTEMPTS) { reconnectAttempts.current++; console.log( `[WebSocket] Reconnecting in ${RECONNECT_DELAY}ms ` + `(attempt ${reconnectAttempts.current}/${MAX_RECONNECT_ATTEMPTS})` ); reconnectTimeout.current = setTimeout(() =&gt; { connect(); }, RECONNECT_DELAY); } }; wsRef.current = ws; }, [videoId, updateProgress]); const disconnect = useCallback(() =&gt; { if (reconnectTimeout.current) { clearTimeout(reconnectTimeout.current); } if (wsRef.current) { wsRef.current.close(); wsRef.current = null; } }, []); useEffect(() =&gt; { connect(); return () =&gt; { disconnect(); }; }, [connect, disconnect]); return { disconnect, reconnect: connect }; } Step 4: Video Player Component Video Player with Subtitle Overlay // src/components/VideoPlayer.tsx import { useRef, useState, useEffect } from &#39;react&#39;; interface Subtitle { index: number; start: number; // seconds end: number; // seconds text: string; } interface VideoPlayerProps { src: string; subtitles?: Subtitle[]; onTimeUpdate?: (currentTime: number) =&gt; void; } export function VideoPlayer({ src, subtitles = [], onTimeUpdate }: VideoPlayerProps) { const videoRef = useRef&lt;HTMLVideoElement&gt;(null); const [currentSubtitle, setCurrentSubtitle] = useState&lt;Subtitle | null&gt;(null); // Find current subtitle based on playback time useEffect(() =&gt; { const video = videoRef.current; if (!video || subtitles.length === 0) return; const updateSubtitle = () =&gt; { const currentTime = video.currentTime; const subtitle = subtitles.find( (sub) =&gt; currentTime &gt;= sub.start &amp;&amp; currentTime &lt;= sub.end ); setCurrentSubtitle(subtitle || null); if (onTimeUpdate) { onTimeUpdate(currentTime); } }; video.addEventListener(&#39;timeupdate&#39;, updateSubtitle); return () =&gt; { video.removeEventListener(&#39;timeupdate&#39;, updateSubtitle); }; }, [subtitles, onTimeUpdate]); return ( &lt;div className=&#34;relative w-full aspect-video bg-black rounded-lg overflow-hidden&#34;&gt; {/* Video Element */} &lt;video ref={videoRef} src={src} className=&#34;w-full h-full object-contain&#34; controls playsInline /&gt; {/* Subtitle Overlay */} {currentSubtitle &amp;&amp; ( &lt;div className=&#34;absolute bottom-16 left-0 right-0 text-center pointer-events-none&#34; aria-live=&#34;polite&#34; &gt; &lt;span className=&#34;inline-block px-4 py-2 bg-black/80 text-white text-xl rounded&#34; style={{ maxWidth: &#39;90%&#39; }} &gt; {currentSubtitle.text} &lt;/span&gt; &lt;/div&gt; )} &lt;/div&gt; ); } Video Player with Hard Subtitle Overlay // src/components/VideoPlayerWithOverlay.tsx import { useState, useRef } from &#39;react&#39;; interface VideoPlayerWithOverlayProps { videoSrc: string; subtitleSrc?: string; } export function VideoPlayerWithOverlay({ videoSrc, subtitleSrc }: VideoPlayerWithOverlayProps) { const videoRef = useRef&lt;HTMLVideoElement&gt;(null); const [currentTime, setCurrentTime] = useState(0); const [duration, setDuration] = useState(0); const [showOverlay, setShowOverlay] = useState(true); // Parse SRT and convert to time-based lookup const subtitles = useMemo(() =&gt; { if (!subtitleSrc) return []; // SRT parsing logic here // Return array of { start, end, text } objects }, [subtitleSrc]); const currentSubtitle = useMemo(() =&gt; { return subtitles.find( (sub) =&gt; currentTime &gt;= sub.start &amp;&amp; currentTime &lt;= sub.end ); }, [subtitles, currentTime]); const handleTimeUpdate = () =&gt; { if (videoRef.current) { setCurrentTime(videoRef.current.currentTime); } }; const handleLoadedMetadata = () =&gt; { if (videoRef.current) { setDuration(videoRef.current.duration); } }; return ( &lt;div className=&#34;relative w-full&#34;&gt; {/* Video Player */} &lt;video ref={videoRef} src={videoSrc} controls onTimeUpdate={handleTimeUpdate} onLoadedMetadata={handleLoadedMetadata} className=&#34;w-full rounded-lg&#34; /&gt; {/* Subtitle Overlay */} {showOverlay &amp;&amp; currentSubtitle &amp;&amp; ( &lt;div className=&#34;absolute bottom-12 left-0 right-0 flex justify-center&#34;&gt; &lt;div className=&#34;bg-black/80 text-white px-6 py-3 rounded-lg text-center max-w-3xl&#34;&gt; &lt;p className=&#34;text-lg leading-relaxed&#34;&gt; {currentSubtitle.text} &lt;/p&gt; &lt;/div&gt; &lt;/div&gt; )} {/* Toggle Overlay Button */} &lt;button onClick={() =&gt; setShowOverlay(!showOverlay)} className=&#34;absolute top-4 right-4 bg-black/60 text-white px-3 py-1 rounded text-sm&#34; &gt; {showOverlay ? &#39;Hide Subtitles&#39; : &#39;Show Subtitles&#39;} &lt;/button&gt; &lt;/div&gt; ); } Step 5: Subtitle Editor with Auto-Save Editor Hook // src/hooks/useSubtitleSync.ts import { useState, useEffect, useCallback, useRef } from &#39;react&#39;; import { debounce } from &#39;@/lib/utils&#39;; interface Subtitle { id: string; start: number; end: number; text: string; } interface UseSubtitleSyncProps { subtitles: Subtitle[]; videoId: string; onSave: (subtitles: Subtitle[]) =&gt; Promise&lt;void&gt;; debounceMs?: number; } export function useSubtitleSync({ subtitles, videoId, onSave, debounceMs = 1000 }: UseSubtitleSyncProps) { const [localSubtitles, setLocalSubtitles] = useState&lt;Subtitle[]&gt;(subtitles); const [isSaving, setIsSaving] = useState(false); const [lastSaved, setLastSaved] = useState&lt;Date | null&gt;(null); const [hasChanges, setHasChanges] = useState(false); // Update local state when props change useEffect(() =&gt; { setLocalSubtitles(subtitles); }, [subtitles]); // Debounced save function const debouncedSave = useRef( debounce(async (subtitlesToSave: Subtitle[]) =&gt; { setIsSaving(true); try { await onSave(subtitlesToSave); setLastSaved(new Date()); setHasChanges(false); } catch (error) { console.error(&#39;Failed to save subtitles:&#39;, error); } finally { setIsSaving(false); } }, debounceMs) ).current; // Update subtitle text const updateSubtitle = useCallback((id: string, text: string) =&gt; { setLocalSubtitles((prev) =&gt; prev.map((sub) =&gt; sub.id === id ? { ...sub, text } : sub ) ); setHasChanges(true); debouncedSave(localSubtitles); }, [debouncedSave, localSubtitles]); // Adjust subtitle timing const adjustSubtitle = useCallback(( id: string, field: &#39;start&#39; | &#39;end&#39;, delta: number ) =&gt; { setLocalSubtitles((prev) =&gt; prev.map((sub) =&gt; sub.id === id ? { ...sub, [field]: Math.max(0, sub[field] + delta) } : sub ) ); setHasChanges(true); debouncedSave(localSubtitles); }, [debouncedSave, localSubtitles]); // Delete subtitle const deleteSubtitle = useCallback((id: string) =&gt; { setLocalSubtitles((prev) =&gt; prev.filter((sub) =&gt; sub.id !== id)); setHasChanges(true); debouncedSave(localSubtitles); }, [debouncedSave, localSubtitles]); // Add new subtitle const addSubtitle = useCallback((afterId: string) =&gt; { const index = localSubtitles.findIndex((s) =&gt; s.id === afterId); if (index === -1) return; const current = localSubtitles[index]; const next = localSubtitles[index + 1]; const newSubtitle: Subtitle = { id: `sub_${Date.now()}`, start: current.end, end: next ? next.start : current.end + 3, text: &#39;&#39; }; const newSubtitles = [ ...localSubtitles.slice(0, index + 1), newSubtitle, ...localSubtitles.slice(index + 1) ]; setLocalSubtitles(newSubtitles); setHasChanges(true); debouncedSave(newSubtitles); }, [localSubtitles, debouncedSave]); return { subtitles: localSubtitles, isSaving, lastSaved, hasChanges, updateSubtitle, adjustSubtitle, deleteSubtitle, addSubtitle }; } Subtitle Editor Component // src/components/SubtitleEditor.tsx import { useState } from &#39;react&#39;; import { useSubtitleSync } from &#39;@/hooks/useSubtitleSync&#39;; import { formatTime } from &#39;@/lib/utils&#39;; interface SubtitleEditorProps { videoId: string; subtitles: Subtitle[]; onSave: (subtitles: Subtitle[]) =&gt; Promise&lt;void&gt;; } export function SubtitleEditor({ videoId, subtitles, onSave }: SubtitleEditorProps) { const { subtitles: localSubtitles, isSaving, lastSaved, hasChanges, updateSubtitle, adjustSubtitle, deleteSubtitle } = useSubtitleSync({ subtitles, videoId, onSave }); const [selectedId, setSelectedId] = useState&lt;string | null&gt;(null); return ( &lt;div className=&#34;flex flex-col h-full&#34;&gt; {/* Header with save status */} &lt;div className=&#34;flex items-center justify-between px-4 py-3 border-b&#34;&gt; &lt;h2 className=&#34;text-lg font-semibold&#34;&gt;Subtitle Editor&lt;/h2&gt; &lt;div className=&#34;flex items-center gap-4&#34;&gt; {/* Save indicator */} &lt;div className=&#34;text-sm text-gray-500&#34;&gt; {isSaving ? ( &lt;span className=&#34;flex items-center gap-2&#34;&gt; &lt;span className=&#34;w-2 h-2 bg-yellow-500 rounded-full animate-pulse&#34; /&gt; Saving... &lt;/span&gt; ) : lastSaved ? ( &lt;span className=&#34;flex items-center gap-2&#34;&gt; &lt;span className=&#34;w-2 h-2 bg-green-500 rounded-full&#34; /&gt; Saved {formatTime(lastSaved.getTime())} &lt;/span&gt; ) : hasChanges ? ( &lt;span className=&#34;flex items-center gap-2&#34;&gt; &lt;span className=&#34;w-2 h-2 bg-gray-400 rounded-full&#34; /&gt; Unsaved changes &lt;/span&gt; ) : null} &lt;/div&gt; &lt;/div&gt; &lt;/div&gt; {/* Subtitle list */} &lt;div className=&#34;flex-1 overflow-y-auto&#34;&gt; {localSubtitles.map((sub, index) =&gt; ( &lt;div key={sub.id} className={`px-4 py-3 border-b ${ selectedId === sub.id ? &#39;bg-blue-50&#39; : &#39;hover:bg-gray-50&#39; }`} onClick={() =&gt; setSelectedId(sub.id)} &gt; {/* Time display */} &lt;div className=&#34;flex items-center gap-2 text-sm text-gray-600 mb-2&#34;&gt; &lt;span className=&#34;font-mono&#34;&gt; {formatTime(sub.start)} → {formatTime(sub.end)} &lt;/span&gt; &lt;span className=&#34;text-gray-400&#34;&gt;#{index + 1}&lt;/span&gt; &lt;/div&gt; {/* Text input */} &lt;textarea value={sub.text} onChange={(e) =&gt; updateSubtitle(sub.id, e.target.value)} className=&#34;w-full px-3 py-2 border rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500&#34; rows={2} placeholder=&#34;Enter subtitle text...&#34; /&gt; {/* Time adjustment buttons */} &lt;div className=&#34;flex items-center gap-2 mt-2&#34;&gt; &lt;button onClick={(e) =&gt; { e.stopPropagation(); adjustSubtitle(sub.id, &#39;start&#39;, -0.1); }} className=&#34;px-2 py-1 text-xs bg-gray-100 rounded hover:bg-gray-200&#34; &gt; -0.1s &lt;/button&gt; &lt;button onClick={(e) =&gt; { e.stopPropagation(); adjustSubtitle(sub.id, &#39;start&#39;, 0.1); }} className=&#34;px-2 py-1 text-xs bg-gray-100 rounded hover:bg-gray-200&#34; &gt; +0.1s &lt;/button&gt; &lt;button onClick={(e) =&gt; { e.stopPropagation(); deleteSubtitle(sub.id); }} className=&#34;px-2 py-1 text-xs text-red-600 bg-red-50 rounded hover:bg-red-100 ml-auto&#34; &gt; Delete &lt;/button&gt; &lt;/div&gt; &lt;/div&gt; ))} &lt;/div&gt; &lt;/div&gt; ); } Step 6: Video Upload Component // src/components/VideoUploader.tsx import { useState, useCallback } from &#39;react&#39;; import { useVideoStore } from &#39;@/store/use-video-store&#39;; import { useAuthStore } from &#39;@/store/use-auth-store&#39;; import axios from &#39;axios&#39;; export function VideoUploader() { const [isUploading, setIsUploading] = useState(false); const [uploadProgress, setUploadProgress] = useState(0); const [dragActive, setDragActive] = useState(false); const addVideo = useVideoStore((state) =&gt; state.addVideo); const token = useAuthStore((state) =&gt; state.token); const handleUpload = useCallback(async (file: File) =&gt; { if (!file.type.startsWith(&#39;video/&#39;)) { alert(&#39;Please upload a video file&#39;); return; } setIsUploading(true); setUploadProgress(0); const formData = new FormData(); formData.append(&#39;file&#39;, file); try { const response = await axios.post( `${import.meta.env.VITE_API_URL}/api/v1/videos/upload`, formData, { headers: { &#39;Authorization&#39;: `Bearer ${token}`, &#39;Content-Type&#39;: &#39;multipart/form-data&#39; }, onUploadProgress: (progressEvent) =&gt; { const progress = Math.round( (progressEvent.loaded * 100) / (progressEvent.total || 1) ); setUploadProgress(progress); } } ); // Add to store addVideo({ videoId: response.data.video_id, title: response.data.title, fileName: response.data.file_name, fileUrl: response.data.file_url, videoUrl: response.data.file_url, thumbnailUrl: null, status: &#39;PROCESSING&#39;, processingPercentage: 0, voiceUsed: null, createdAt: new Date().toISOString() }); alert(&#39;Video uploaded successfully! Processing will begin shortly.&#39;); } catch (error) { console.error(&#39;Upload failed:&#39;, error); alert(&#39;Upload failed. Please try again.&#39;); } finally { setIsUploading(false); } }, [token, addVideo]); const handleDrop = useCallback((e: React.DragEvent) =&gt; { e.preventDefault(); setDragActive(false); const files = e.dataTransfer.files; if (files.length &gt; 0) { handleUpload(files[0]); } }, [handleUpload]); return ( &lt;div className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors ${ dragActive ? &#39;border-blue-500 bg-blue-50&#39; : &#39;border-gray-300&#39; }`} onDragOver={(e) =&gt; { e.preventDefault(); setDragActive(true); }} onDragLeave={() =&gt; setDragActive(false)} onDrop={handleDrop} &gt; &lt;input type=&#34;file&#34; accept=&#34;video/*&#34; onChange={(e) =&gt; { if (e.target.files?.[0]) { handleUpload(e.target.files[0]); } }} className=&#34;hidden&#34; id=&#34;video-upload&#34; /&gt; &lt;label htmlFor=&#34;video-upload&#34; className=&#34;cursor-pointer&#34;&gt; &lt;div className=&#34;flex flex-col items-center gap-4&#34;&gt; &lt;div className=&#34;w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center&#34;&gt; &lt;UploadIcon className=&#34;w-8 h-8 text-blue-600&#34; /&gt; &lt;/div&gt; &lt;div&gt; &lt;p className=&#34;text-lg font-medium text-gray-700&#34;&gt; Drop your video here or click to upload &lt;/p&gt; &lt;p className=&#34;text-sm text-gray-500 mt-1&#34;&gt; Supported formats: MP4, MOV, AVI, MKV &lt;/p&gt; &lt;/div&gt; {isUploading &amp;&amp; ( &lt;div className=&#34;w-full max-w-xs mt-4&#34;&gt; &lt;div className=&#34;h-2 bg-gray-200 rounded-full overflow-hidden&#34;&gt; &lt;div className=&#34;h-full bg-blue-600 transition-all&#34; style={{ width: `${uploadProgress}%` }} /&gt; &lt;/div&gt; &lt;p className=&#34;text-sm text-gray-500 mt-2&#34;&gt; Uploading... {uploadProgress}% &lt;/p&gt; &lt;/div&gt; )} &lt;/div&gt; &lt;/label&gt; &lt;/div&gt; ); } Code References Component File Description Video Store src/store/use-video-store.ts Video state management Auth Store src/store/use-auth-store.ts Authentication state Progress Hook src/hooks/useVideoProgress.ts WebSocket client Subtitle Sync src/hooks/useSubtitleSync.ts Auto-save logic Video Player src/components/VideoPlayer.tsx Basic player Player Overlay src/components/VideoPlayerWithOverlay.tsx Subtitle display Subtitle Editor src/components/SubtitleEditor.tsx In-browser editing Video Uploader src/components/VideoUploader.tsx Upload interface Summary In this module, you learned:
Zustand Stores: Video and authentication state management WebSocket Client: Real-time progress tracking with auto-reconnect Video Player: Components with subtitle overlay support Auto-Save: Debounced saving with visual feedback Subtitle Editor: In-browser editing with timing adjustment Upload Component: Drag-and-drop video upload Validation Test the frontend:
# Start development server cd myapporc npm run dev # Check for TypeScript errors npm run type-check # Build for production npm run build
